class Solution {
public:
    int strongPasswordChecker(string password) {
        int missingTypes = 3;
        if (any_of(password.begin(), password.end(), ::islower)) missingTypes--;
        if (any_of(password.begin(), password.end(), ::isupper)) missingTypes--;
        if (any_of(password.begin(), password.end(), ::isdigit)) missingTypes--;

        int n = password.size();
        int oneRepeating = 0, twoRepeating = 0;
        int count = 1;
        for (int i = 1; i < n; ++i) {
            if (password[i] == password[i - 1]) count++;
            else {
                if (count >= 3) {
                    int remainder = count % 3;
                    if (remainder == 0) oneRepeating++;
                    else if (remainder == 1) twoRepeating++;
                }
                count = 1;
            }
        }
        if (count >= 3) {
            int remainder = count % 3;
            if (remainder == 0) oneRepeating++;
            else if (remainder == 1) twoRepeating++;
        }

        if (n < 6) {
            return max(6 - n, missingTypes);
        } else if (n <= 20) {
            return max(missingTypes, oneRepeating + twoRepeating);
        } else {
            int deletions = n - 20;
            oneRepeating -= min(deletions, oneRepeating);
            twoRepeating -= min(max(deletions - oneRepeating, 0), twoRepeating * 2) / 2;
            return deletions + max(missingTypes, oneRepeating + twoRepeating);
        }
    }
};
